   433→/**
   434→ * Props for the Widget wrapper component
   435→ *
   436→ * Widgets are the primary dashboard building blocks. Each widget
   437→ * displays in a card with optional header, drag controls, and
   438→ * built-in loading/error state handling.
   439→ *
   440→ * @example
   441→ * ```tsx
   442→ * <Widget
   443→ *   id="weather"
   444→ *   title="Weather"
   445→ *   category="Information"
   446→ *   loading={isLoading}
   447→ *   error={fetchError}
   448→ *   onRefresh={refetch}
   449→ * >
   450→ *   <WeatherDisplay data={weatherData} />
   451→ * </Widget>
   452→ * ```
   453→ */
   454→export interface WidgetProps {
   455→  /** Unique identifier for the widget (used for persistence) */
   456→  id: string;
   457→  /** Display title shown in widget header */
   458→  title: string;
   459→  /** Category label (e.g., "Information", "Productivity") */
   460→  category?: string;
   461→  /** Additional CSS classes for the widget container */
   462→  className?: string;
   463→  /** Widget content - rendered when not loading/error */
   464→  children?: React.ReactNode;
   465→  /** Optional content displayed in header (e.g., weather stats) */
   466→  headerAccessory?: React.ReactNode;
   467→  /** Whether to show drag handle (default: true) */
   468→  draggable?: boolean;
   469→  /** Shows loading spinner instead of children when true */
   470→  loading?: boolean;
   471→  /** Shows error message with retry option when set */
   472→  error?: string | null;
   473→  /** Callback for retry/refresh button (enables refresh button in header) */
   474→  onRefresh?: () => void;
   475→}
