     1→import Dexie from 'dexie';
     2→import type { Table } from 'dexie';
     3→import type { TimeEntry, TimeTrackingProject } from '../types';
     4→
     5→/**
     6→ * Time Tracking Database using Dexie.js for IndexedDB
     7→ * Handles efficient storage and querying of time entries and projects
     8→ */
     9→class TimeTrackingDatabase extends Dexie {
    10→  timeEntries!: Table<TimeEntry, string>;
    11→  projects!: Table<TimeTrackingProject, string>;
    12→
    13→  constructor() {
    14→    super('NeumanBrainTimeTracking');
    15→
    16→    // Schema version 1
    17→    this.version(1).stores({
    18→      timeEntries: 'id, projectId, taskId, startTime, endTime, [projectId+startTime], description',
    19→      projects: 'id, name, active, archived'
    20→    });
    21→  }
    22→}
    23→
    24→// Create database instance
    25→export const db = new TimeTrackingDatabase();
    26→
    27→/**
    28→ * Time Tracking Database Helper Functions
    29→ * Provides a clean API for database operations
    30→ */
    31→export const timeTrackingDb = {
    32→  // ==================== TIME ENTRIES ====================
    33→
    34→  /**
    35→   * Add a new time entry
    36→   */
    37→  async addEntry(entry: TimeEntry): Promise<void> {
    38→    await db.timeEntries.add(entry);
    39→  },
    40→
    41→  /**
    42→   * Get time entries with optional filters
    43→   */
    44→  async getEntries(filters?: {
    45→    startDate?: Date;
    46→    endDate?: Date;
    47→    projectId?: string;
    48→    searchQuery?: string;
    49→  }): Promise<TimeEntry[]> {
    50→    let collection = db.timeEntries.orderBy('startTime').reverse();
    51→
    52→    if (filters?.startDate && filters?.endDate) {
    53→      collection = collection.filter(entry => {
    54→        const entryDate = new Date(entry.startTime);
    55→        return entryDate >= filters.startDate! && entryDate <= filters.endDate!;
    56→      });
    57→    }
    58→
    59→    if (filters?.projectId) {
    60→      collection = collection.filter(entry => entry.projectId === filters.projectId);
    61→    }
    62→
    63→    if (filters?.searchQuery) {
    64→      const query = filters.searchQuery.toLowerCase();
    65→      collection = collection.filter(entry =>
    66→        entry.description.toLowerCase().includes(query) ||
    67→        (entry.notes?.toLowerCase().includes(query) ?? false)
    68→      );
    69→    }
    70→
    71→    return await collection.toArray();
    72→  },
    73→
    74→  /**
    75→   * Get a single time entry by ID
    76→   */
    77→  async getEntry(id: string): Promise<TimeEntry | undefined> {
    78→    return await db.timeEntries.get(id);
    79→  },
    80→
    81→  /**
    82→   * Update a time entry
    83→   */
    84→  async updateEntry(id: string, updates: Partial<TimeEntry>): Promise<void> {
    85→    await db.timeEntries.update(id, {
    86→      ...updates,
    87→      updatedAt: new Date().toISOString()
    88→    });
    89→  },
    90→
    91→  /**
    92→   * Delete a time entry
    93→   */
    94→  async deleteEntry(id: string): Promise<void> {
    95→    await db.timeEntries.delete(id);
    96→  },
    97→
    98→  /**
    99→   * Get entries for a specific date range (optimized for reports)
   100→   */
   101→  async getEntriesByDateRange(startDate: Date, endDate: Date): Promise<TimeEntry[]> {
   102→    return await db.timeEntries
   103→      .where('startTime')
   104→      .between(startDate.toISOString(), endDate.toISOString(), true, true)
   105→      .reverse()
   106→      .toArray();
   107→  },
   108→
   109→  /**
   110→   * Get all entries for a specific project
   111→   */
   112→  async getEntriesByProject(projectId: string): Promise<TimeEntry[]> {
   113→    return await db.timeEntries
   114→      .where('projectId')
   115→      .equals(projectId)
   116→      .reverse()
   117→      .toArray();
   118→  },
   119→
   120→  /**
   121→   * Get all entries for a specific task (Kanban integration)
   122→   */
   123→  async getEntriesByTask(taskId: string): Promise<TimeEntry[]> {
