      if (idleTimerRef.current) {
        clearTimeout(idleTimerRef.current);
      }
      if (throttleTimer) {
        clearTimeout(throttleTimer);
      }
    };
  }, [enabled, resetIdleTimer]);

  // Calculate current idle duration
  const idleDuration = isIdle && idleSince !== null ? Date.now() - idleSince : 0;

  return {
    isIdle,
    idleSince,
    idleDuration,
    lastActivity
  };
}

