export function TimeTrackingTimer() {
  // Time tracking state from store
  const {
    activeEntry,
    entries,
    projects,
    startTimer,
    stopTimer,
    pauseTimer,
    resumeTimer,
    updateTimerDescription,
    updateActiveEntry,
    continueEntry,
    getRecentEntries,
    getTodayTotal,
    getWeeklySummary,
    isTimerRunning,
    timerDescription,
    timerProjectId,
