      </div>

      {/* Filters */}
      <div className="rounded-lg bg-surface-elevated p-4">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {/* Report Type */}
          <div>
            <label className="block text-sm font-medium text-text-primary mb-1">
              Report Type
            </label>
            <select
              value={reportType}
              onChange={(e) => setReportType(e.target.value as ReportType)}
              className="w-full rounded-md border border-border-light bg-surface-base px-3 py-2 text-sm text-text-primary focus:border-accent-primary focus:outline-none"
            >
              {REPORT_TYPES.map(type => (
                <option key={type.value} value={type.value}>
                  {type.label}
                </option>
              ))}
            </select>
          </div>

          {/* Start Date */}
          <div>
            <label className="block text-sm font-medium text-text-primary mb-1">
              Start Date
            </label>
            <input
              type="date"
              value={filters.startDate}
              onChange={(e) => setFilters({ ...filters, startDate: e.target.value })}
              className="w-full rounded-md border border-border-light bg-surface-base px-3 py-2 text-sm text-text-primary focus:border-accent-primary focus:outline-none"
            />
          </div>

          {/* End Date */}
          <div>
            <label className="block text-sm font-medium text-text-primary mb-1">
              End Date
            </label>
            <input
              type="date"
              value={filters.endDate}
              onChange={(e) => setFilters({ ...filters, endDate: e.target.value })}
              className="w-full rounded-md border border-border-light bg-surface-base px-3 py-2 text-sm text-text-primary focus:border-accent-primary focus:outline-none"
            />
          </div>

          {/* Group By (for applicable reports) */}
          {(reportType === 'time-by-date' || reportType === 'trends') && (
            <div>
              <label className="block text-sm font-medium text-text-primary mb-1">
                Group By
              </label>
              <select
                value={filters.groupBy}
                onChange={(e) => setFilters({ ...filters, groupBy: e.target.value as GroupByPeriod })}
                className="w-full rounded-md border border-border-light bg-surface-base px-3 py-2 text-sm text-text-primary focus:border-accent-primary focus:outline-none"
